query:
SELECT id, poNumber, batchNo, serialNumber, imei, productName, archivedAt, createdAt, updatedAt
FROM products
WHERE batchNo = 'NO-IMPORT-BATCH-1778749383598'
ORDER BY id DESC;

SELECT poNumber, deletedProducts, deletedTasks, deletedByName, createdAt
FROM purchase_order_deletion_logs
WHERE poNumber IN (
  SELECT DISTINCT poNumber FROM products WHERE batchNo = 'NO-IMPORT-BATCH-1778749383598'
)
ORDER BY createdAt DESC;

